questionvariables.text:
/* Randomize diagonals d1 and d2 between 6 and 20 */
/* We use a while loop to ensure they aren't the same number */
d1: 6 + rand(15);
d2: 6 + rand(15);
while d1 = d2 do (
    d2: 6 + rand(15)
);

/* Calculate the correct area */
/* Area = 1/2 * d1 * d2 */
ta: (1/2) * d1 * d2;
